    def _build_water_surfs(self):
        surfs = []
        for level in range(1, 9):
            h = max(4, level * BLOCK_SIZE // 8)   # level 1=4px … level 8=32px
            s = pygame.Surface((BLOCK_SIZE, h), pygame.SRCALPHA)
            alpha = 110 + level * 7               # deeper = more opaque
            s.fill((40, 110, 220, alpha))
            shimmer = pygame.Surface((BLOCK_SIZE, 2), pygame.SRCALPHA)
            shimmer.fill((100, 180, 255, 55))
            for ry in range(3, h - 1, 9):
                s.blit(shimmer, (0, ry))
            surfs.append(s)
        return surfs

    def _build_resource_hint_surfs(self):
        stone_col = BLOCKS[STONE]["color"]
        hints = {}
        for bid in RESOURCE_BLOCKS:
            res_col  = BLOCKS[bid]["color"]
            hint_col = tuple(int(stone_col[i] * 0.8 + res_col[i] * 0.2) for i in range(3))
            s = pygame.Surface((BLOCK_SIZE, BLOCK_SIZE))
            s.fill(hint_col)
            pygame.draw.rect(s, _darken(hint_col), s.get_rect(), 1)
            hints[bid] = s
        return hints

    def _build_biome_resource_hint_surfs(self):
        result = {}
        for biome, stone_col in BIOME_STONE_COLORS.items():
            hints = {}
            for bid in RESOURCE_BLOCKS:
                res_col = BLOCKS[bid]["color"]
                hint_col = tuple(int(stone_col[i] * 0.8 + res_col[i] * 0.2) for i in range(3))
                s = pygame.Surface((BLOCK_SIZE, BLOCK_SIZE))
                s.fill(hint_col)
                pygame.draw.rect(s, _darken(hint_col), s.get_rect(), 1)
                hints[bid] = s
            result[biome] = hints
        return result

    def _build_biome_stone_surfs(self):
        surfs = {}
        for biome, color in BIOME_STONE_COLORS.items():
            s = pygame.Surface((BLOCK_SIZE, BLOCK_SIZE))
            s.fill(color)
            pygame.draw.rect(s, _darken(color), s.get_rect(), 1)
            surfs[biome] = s
        return surfs

    def _get_town_flag_surf(self, region_id, flag_col):
        """Return a lazily-built flag surface tinted with the region's primary color."""
        if region_id not in self._town_flag_surfs:
            BS = BLOCK_SIZE
            s = pygame.Surface((BS, BS), pygame.SRCALPHA)
            s.fill((0, 0, 0, 0))
            pole = (120, 100, 70)
            pygame.draw.rect(s, pole, (BS // 2 - 2, 0, 3, BS))
            pts = [(BS // 2 + 1, 3), (BS - 4, 9), (BS // 2 + 1, 16)]
            pygame.draw.polygon(s, flag_col, pts)
            pygame.draw.polygon(s, _darken(flag_col), pts, 1)
            self._town_flag_surfs[region_id] = s
        return self._town_flag_surfs[region_id]

    def _get_outpost_flag_surf(self, outpost_type, flag_col):
        """Return a lazily-built flag surface tinted with the outpost type's color."""
        if outpost_type not in self._outpost_flag_surfs:
            BS = BLOCK_SIZE
            s = pygame.Surface((BS, BS), pygame.SRCALPHA)
            s.fill((0, 0, 0, 0))
            pole = (120, 100, 70)
            pygame.draw.rect(s, pole, (BS // 2 - 2, 0, 3, BS))
            pts = [(BS // 2 + 1, 3), (BS - 4, 9), (BS // 2 + 1, 16)]
            pygame.draw.polygon(s, flag_col, pts)
            pygame.draw.polygon(s, _darken(flag_col), pts, 1)
            self._outpost_flag_surfs[outpost_type] = s
        return self._outpost_flag_surfs[outpost_type]

    def _build_log_variants(self):
        # 8 variants per log type
        # Trunk widths: full, full, medium(18), thin(12), full×4
        # Brightness shifts and texture details differ per variant
        trunk_widths  = [BLOCK_SIZE, BLOCK_SIZE, 18, 12, BLOCK_SIZE, BLOCK_SIZE, 18, BLOCK_SIZE]
        bright_shifts = [0, 18, 0, -14, 0, 14, -8, 0]
        grain_gaps    = [5,  4,  5,   4,  6,   5,  4,  5]
        variants = {}
        for bid in ALL_LOGS:
            bdata = BLOCKS.get(bid)
            if not bdata or not bdata.get("color"):
                continue
            base = bdata["color"]
            surfs = []
            for v in range(8):
                shift = bright_shifts[v]
                tone  = tuple(max(0, min(255, c + shift)) for c in base)
                dark  = _darken(tone, 32)
                tw    = trunk_widths[v]
                cx    = (BLOCK_SIZE - tw) // 2
                gs    = grain_gaps[v]
                s = pygame.Surface((BLOCK_SIZE, BLOCK_SIZE))
                side_col = _darken(tone, 50)
                s.fill(side_col if tw < BLOCK_SIZE else tone)
                if tw < BLOCK_SIZE:
                    pygame.draw.rect(s, tone, (cx, 0, tw, BLOCK_SIZE))
                # Vertical grain lines
                grain = _darken(tone, 24)
                for gx in range(cx + 3, cx + tw - 2, gs):
                    pygame.draw.line(s, grain, (gx, 1), (gx, BLOCK_SIZE - 2), 1)
                # Highlight stripe
                hi = tuple(min(255, c + 14) for c in tone)
                if cx + 2 < cx + tw - 1:
                    pygame.draw.line(s, hi, (cx + 2, 1), (cx + 2, BLOCK_SIZE - 2), 1)
                # v4: knot — dark oval near centre
                if v == 4:
                    kx, ky = BLOCK_SIZE // 2, BLOCK_SIZE // 2 + 4
                    knot = _darken(tone, 55)
                    pygame.draw.ellipse(s, knot,             (kx - 4, ky - 3, 8, 6))
                    pygame.draw.ellipse(s, _darken(knot, 20),(kx - 2, ky - 1, 4, 3))
                # v5: moss patches
                if v == 5:
                    moss = (max(0, tone[0] - 22), min(255, tone[1] + 32), max(0, tone[2] - 22))
                    for mx, my in [(4, 2), (BLOCK_SIZE - 10, 5),
                                   (6, BLOCK_SIZE - 10), (BLOCK_SIZE - 8, BLOCK_SIZE - 8)]:
                        pygame.draw.rect(s, moss,             (mx, my, 5, 4))
                        pygame.draw.rect(s, _darken(moss, 18),(mx + 1, my + 1, 3, 2))
                # v7: horizontal bark rings
                if v == 7:
                    ring = _darken(tone, 28)
                    for ry in range(4, BLOCK_SIZE - 2, 7):
                        pygame.draw.line(s, ring, (cx + 1, ry), (cx + tw - 2, ry), 1)
                border_rect = (cx, 0, tw, BLOCK_SIZE) if tw < BLOCK_SIZE else s.get_rect()
                pygame.draw.rect(s, dark, border_rect, 1)
                surfs.append(s)
            variants[bid] = surfs
        return variants

    def _build_leaf_variants(self):
        # 8 variants: 4 solid (base, light, very-light, dark) + 4 speckled
        # v6 gets an autumn warm-shift; v7 gets a darkened interior (shadow depth)
        bright_shifts = [0, 20, 38, -16, 0, 20, 0, -16]
        speckled      = [False, False, False, False, True, True, True, True]
        _spots  = [(3,3),(9,11),(15,4),(21,8),(27,2),(5,19),(12,24),(19,17),(25,21),(7,28),(22,27),(14,14)]
        _bright = [(6,7),(18,5),(11,20),(24,15)]
        variants = {}
        for bid in ALL_LEAVES:
            bdata = BLOCKS.get(bid)
            if not bdata or not bdata.get("color"):
                continue
            base = bdata["color"]
            surfs = []
            for v in range(8):
                shift = bright_shifts[v]
                tone  = tuple(max(0, min(255, c + shift)) for c in base)
                # v6: autumn — warm shift (boost red, pull green/blue)
                if v == 6:
                    tone = (min(255, tone[0] + 28), max(0, tone[1] - 12), max(0, tone[2] - 18))
                dark  = _darken(tone, 28)
                s = pygame.Surface((BLOCK_SIZE, BLOCK_SIZE))
                s.fill(tone)
                if speckled[v]:
                    spot_col   = _darken(tone, 40)
                    bright_col = tuple(min(255, c + 20) for c in tone)
                    for sx2, sy2 in _spots:
                        if sx2 + 3 <= BLOCK_SIZE and sy2 + 3 <= BLOCK_SIZE:
                            pygame.draw.rect(s, spot_col, (sx2, sy2, 3, 3))
                    for sx2, sy2 in _bright:
                        if sx2 + 2 <= BLOCK_SIZE and sy2 + 2 <= BLOCK_SIZE:
                            pygame.draw.rect(s, bright_col, (sx2, sy2, 2, 2))
                # v7: deep-shadow interior
                if v == 7:
                    inner = _darken(tone, 22)
                    pygame.draw.rect(s, inner, (2, 2, BLOCK_SIZE - 4, BLOCK_SIZE - 4))
                pygame.draw.rect(s, dark, s.get_rect(), 1)
                surfs.append(s)
            variants[bid] = surfs
        return variants

    def _build_grass_variants(self):
        # 10 variants: plain, lighter, darker, warm-dry, cool-deep, dirt-fleck,
        #              mossy-dark, pale, deep-shadow-patches, bright-spotty
        base = (58, 154, 58)
        bright_shifts = [0, 16, -14, 0, -8, 0, -20, 24, -10, 10]
        surfs = []
        for v in range(10):
            shift = bright_shifts[v]
            tone = tuple(max(0, min(255, c + shift)) for c in base)
            if v == 3:   # warm/dry — yellowish
                tone = (min(255, tone[0]+22), max(0, tone[1]-8), max(0, tone[2]-18))
            elif v == 6: # mossy — pull green deeper, slight blue
                tone = (max(0, tone[0]-8), min(255, tone[1]+6), max(0, tone[2]-4))
            dark = _darken(tone, 28)
            s = pygame.Surface((BLOCK_SIZE, BLOCK_SIZE))
            s.fill(tone)
            if v == 1:   # darker speckles on lighter base
                for px2, py2 in [(4,7),(18,20),(24,5),(11,14),(27,22)]:
                    pygame.draw.rect(s, _darken(tone,18), (px2, py2, 3, 3))
            elif v == 2: # bright spots on darker base
                for px2, py2 in [(7,4),(22,16),(3,24),(15,10),(28,6)]:
                    pygame.draw.rect(s, tuple(min(255,c+22) for c in tone), (px2, py2, 2, 2))
            elif v == 4: # shadow patches
                for px2, py2, pw, ph in [(3,3,4,3),(13,18,3,4),(22,8,2,2),(8,26,4,2)]:
                    pygame.draw.rect(s, _darken(tone,18), (px2, py2, pw, ph))
            elif v == 5: # brown dirt flecks
                for px2, py2 in [(14,22),(6,10),(23,16)]:
                    pygame.draw.rect(s, (105,68,30), (px2, py2, 2, 2))
            elif v == 7: # pale — scattered bright patches
                for px2, py2, pw, ph in [(2,2,5,3),(16,8,4,4),(8,18,3,5),(22,24,5,3)]:
                    hi = tuple(min(255,c+14) for c in tone)
                    pygame.draw.rect(s, hi, (px2, py2, pw, ph))
            elif v == 8: # deep shadow blobs
                for px2, py2, pw, ph in [(1,1,6,5),(18,4,5,6),(3,20,7,4),(20,20,6,7)]:
                    pygame.draw.rect(s, _darken(tone,24), (px2, py2, pw, ph))
            elif v == 9: # bright spotty — many small highlights
                for px2, py2 in [(3,5),(10,2),(17,8),(25,3),(6,16),(20,12),(12,22),(27,18),(4,26),(22,27)]:
                    pygame.draw.rect(s, tuple(min(255,c+20) for c in tone), (px2, py2, 2, 2))
            pygame.draw.rect(s, dark, s.get_rect(), 1)
            surfs.append(s)
        return surfs

    def _build_dirt_variants(self):
        # 10 variants: plain, lighter, darker, reddish-clay, pebbled, speckled,
        #              mixed, pale-sandy, dark-wet, coarse-grained
        base = (115, 77, 38)
        bright_shifts = [0, 18, -14, 0, 0, 0, 0, 26, -18, 0]
        surfs = []
        for v in range(10):
            shift = bright_shifts[v]
            tone = tuple(max(0, min(255, c + shift)) for c in base)
            if v == 3:  # reddish-clay
                tone = (min(255,tone[0]+20), max(0,tone[1]-6), max(0,tone[2]-10))
            elif v == 7: # pale-sandy — warm lighter
                tone = (min(255,tone[0]+8), min(255,tone[1]+14), min(255,tone[2]+22))
            elif v == 8: # dark-wet — desaturated darker
                tone = (max(0,tone[0]-5), max(0,tone[1]-3), max(0,tone[2]+4))
            dark = _darken(tone, 30)
            s = pygame.Surface((BLOCK_SIZE, BLOCK_SIZE))
            s.fill(tone)
            if v == 4:   # pebbles
                for px2, py2 in [(5,5),(16,9),(25,14),(8,22),(20,25),(12,15)]:
                    pygame.draw.rect(s, _darken(tone,42), (px2, py2, 2, 2))
            elif v == 5: # light speckles
                for px2, py2 in [(3,8),(14,3),(22,18),(9,26),(27,6),(18,22)]:
                    pygame.draw.rect(s, tuple(min(255,c+30) for c in tone), (px2, py2, 2, 2))
            elif v == 6: # mixed pebbles + speckles
                for px2, py2 in [(10,12),(5,25),(22,7)]:
                    pygame.draw.rect(s, _darken(tone,40), (px2, py2, 2, 2))
                for px2, py2 in [(22,20),(15,28),(3,16)]:
                    pygame.draw.rect(s, tuple(min(255,c+24) for c in tone), (px2, py2, 2, 2))
            elif v == 8: # dark-wet — subtle horizontal streaks
                for py2 in [6, 14, 22]:
                    pygame.draw.rect(s, _darken(tone,20), (2, py2, BLOCK_SIZE-4, 2))
            elif v == 9: # coarse grain — small dark patches
                for px2, py2, pw, ph in [(2,3,4,3),(14,2,3,4),(24,6,3,3),(6,14,4,3),(19,16,3,4),(3,23,4,3),(22,23,3,3)]:
                    pygame.draw.rect(s, _darken(tone,22), (px2, py2, pw, ph))
            pygame.draw.rect(s, dark, s.get_rect(), 1)
            surfs.append(s)
        return surfs

    def _build_sand_variants(self):
        # 8 variants: plain, lighter, darker, warm-orange, pale-bleached,
        #             ripple-lines, tiny pebbles, damp-dark
        base = (210, 190, 140)
        surfs = []
        for v in range(8):
            tone = base
            if v == 1:   tone = tuple(min(255,c+16) for c in base)
            elif v == 2: tone = tuple(max(0,c-14) for c in base)
            elif v == 3: tone = (min(255,base[0]+18), max(0,base[1]-6), max(0,base[2]-20))  # warm orange
            elif v == 4: tone = (min(255,base[0]+28), min(255,base[1]+22), min(255,base[2]+18))  # bleached
            elif v == 7: tone = (max(0,base[0]-20), max(0,base[1]-16), max(0,base[2]-10))  # damp
            dark = _darken(tone, 26)
            s = pygame.Surface((BLOCK_SIZE, BLOCK_SIZE))
            s.fill(tone)
            if v == 5:   # ripple lines
                for py2 in [5, 12, 19, 26]:
                    pygame.draw.rect(s, _darken(tone,18), (2, py2, BLOCK_SIZE-4, 1))
                    pygame.draw.rect(s, tuple(min(255,c+14) for c in tone), (2, py2+1, BLOCK_SIZE-4, 1))
            elif v == 6: # tiny pebbles
                for px2, py2 in [(4,4),(13,8),(22,5),(7,17),(18,13),(26,20),(10,25),(20,27),(3,24)]:
                    pygame.draw.rect(s, _darken(tone,32), (px2, py2, 2, 2))
            elif v == 7: # damp — diagonal wet streaks
                for i in range(0, BLOCK_SIZE, 8):
                    pygame.draw.rect(s, _darken(tone,24), (i, 0, 2, BLOCK_SIZE))
            pygame.draw.rect(s, dark, s.get_rect(), 1)
            surfs.append(s)
        return surfs

    def _build_snow_variants(self):
        # 8 variants: plain, pure-white, blue-shadow, grey-slush, sparkle,
        #             wind-ridges, deep-drift, packed
        base = (220, 232, 245)
        surfs = []
        for v in range(8):
            tone = base
            if v == 1:   tone = (245, 250, 255)  # pure white
            elif v == 2: tone = (200, 215, 238)  # blue-shadow
            elif v == 3: tone = (210, 212, 215)  # grey slush
            elif v == 4: tone = base
            elif v == 5: tone = (215, 228, 242)  # slightly darker for ridges
            elif v == 6: tone = (230, 240, 252)  # deep drift — brighter
            elif v == 7: tone = (205, 218, 232)  # packed — denser blue
            dark = _darken(tone, 22)
            s = pygame.Surface((BLOCK_SIZE, BLOCK_SIZE))
            s.fill(tone)
            if v == 2:   # blue shadow blobs
                for px2, py2, pw, ph in [(1,1,7,5),(18,3,6,7),(3,20,8,5),(20,22,7,6)]:
                    pygame.draw.rect(s, _darken(tone,16), (px2, py2, pw, ph))
            elif v == 3: # slush — grey smudges
                for px2, py2, pw, ph in [(2,4,5,4),(15,10,6,3),(8,20,5,5),(22,18,4,6)]:
                    pygame.draw.rect(s, (190,192,194), (px2, py2, pw, ph))
            elif v == 4: # sparkle — tiny bright points
                for px2, py2 in [(5,3),(12,9),(21,5),(8,16),(18,14),(26,8),(3,23),(15,26),(24,22),(10,28)]:
                    pygame.draw.rect(s, (255,255,255), (px2, py2, 2, 2))
            elif v == 5: # wind ridges — diagonal lines
                for i in range(-BLOCK_SIZE, BLOCK_SIZE*2, 7):
                    pygame.draw.line(s, tuple(min(255,c+12) for c in tone), (max(0,i),0), (min(BLOCK_SIZE,i+BLOCK_SIZE),min(BLOCK_SIZE,BLOCK_SIZE-i)), 1)
            elif v == 6: # deep drift — subtle highlight blobs
                for px2, py2, pw, ph in [(4,2,8,4),(2,14,6,6),(16,18,7,5),(20,6,5,5)]:
                    pygame.draw.rect(s, tuple(min(255,c+10) for c in tone), (px2, py2, pw, ph))
            elif v == 7: # packed — faint horizontal compression lines
                for py2 in [7, 16, 24]:
                    pygame.draw.rect(s, _darken(tone,14), (1, py2, BLOCK_SIZE-2, 1))
            pygame.draw.rect(s, dark, s.get_rect(), 1)
            surfs.append(s)
        return surfs

    # ------------------------------------------------------------------
    # Camera
    # ------------------------------------------------------------------

    def update_camera(self, player, world):
        target_x = player.x - SCREEN_W // 2 + PLAYER_W // 2
        target_y = player.y - SCREEN_H // 2 + PLAYER_H // 2
        self.cam_x += (target_x - self.cam_x) * 0.12
        self.cam_y += (target_y - self.cam_y) * 0.12
        # Clamp only vertical bounds; horizontal is infinite
        max_cy = world.height * BLOCK_SIZE - SCREEN_H
        self.cam_y = max(0.0, min(self.cam_y, float(max_cy)))

    def _build_sky_surf(self):
        sky_top    = (55,  110, 210)
        sky_bottom = (130, 190, 250)
        surf = pygame.Surface((SCREEN_W, SCREEN_H)).convert()
        for y in range(SCREEN_H):
            t = y / (SCREEN_H - 1)
            r = int(sky_top[0] + (sky_bottom[0] - sky_top[0]) * t)
            g = int(sky_top[1] + (sky_bottom[1] - sky_top[1]) * t)
            b = int(sky_top[2] + (sky_bottom[2] - sky_top[2]) * t)
            pygame.draw.line(surf, (r, g, b), (0, y), (SCREEN_W - 1, y))
        return surf

    def _build_night_sky_surf(self):
        sky_top    = (8,  12, 35)
        sky_bottom = (18, 25, 65)
        surf = pygame.Surface((SCREEN_W, SCREEN_H)).convert()
        for y in range(SCREEN_H):
            t = y / (SCREEN_H - 1)
            r = int(sky_top[0] + (sky_bottom[0] - sky_top[0]) * t)
            g = int(sky_top[1] + (sky_bottom[1] - sky_top[1]) * t)
            b = int(sky_top[2] + (sky_bottom[2] - sky_top[2]) * t)
            pygame.draw.line(surf, (r, g, b), (0, y), (SCREEN_W - 1, y))
        return surf

    def _sky_night_alpha(self, time_of_day):
        # Returns 0 (full day) → 255 (full night), with 60s dawn/dusk transitions
        from world import DAY_DURATION
        DAWN = 60.0
        DUSK = 60.0
        t = time_of_day
        if t < DAWN:
            return int(255 * (1.0 - t / DAWN))
        elif t < DAY_DURATION - DUSK:
            return 0
        elif t < DAY_DURATION:
            return int(255 * ((t - (DAY_DURATION - DUSK)) / DUSK))
        else:
            return 255

    # ------------------------------------------------------------------
    # Draw world
    # ------------------------------------------------------------------

    def draw_world(self, world, player=None):
        self.screen.blit(self._sky_surf, (0, 0))
        night_alpha = self._sky_night_alpha(getattr(world, 'time_of_day', 0.0))
        if night_alpha > 0:
            self._sky_night_surf.set_alpha(night_alpha)
            self.screen.blit(self._sky_night_surf, (0, 0))

        cam_xi = int(self.cam_x)
        cam_yi = int(self.cam_y)

        bx0 = cam_xi // BLOCK_SIZE
        bx1 = (cam_xi + SCREEN_W) // BLOCK_SIZE + 2
        by0 = max(0, cam_yi // BLOCK_SIZE)
        by1 = min(world.height, (cam_yi + SCREEN_H) // BLOCK_SIZE + 2)

        if player is not None:
            px_blk = player.x / BLOCK_SIZE
            py_blk = player.y / BLOCK_SIZE
            detect  = player.rock_detect_range
            warm    = detect + ROCK_WARM_ZONE
        else:
            px_blk = py_blk = detect = warm = None

        # Precompute per-column values to avoid repeated calls inside the block loop
        surface_ys = {bx: world.surface_height(bx) for bx in range(bx0, bx1)}
        biomes = {bx: world.get_biome(bx) for bx in range(bx0, bx1)}

        for by in range(by0, by1):
            for bx in range(bx0, bx1):
                bid = world.get_block(bx, by)
                if bid == AIR:
                    sx = bx * BLOCK_SIZE - cam_xi
                    sy = by * BLOCK_SIZE - cam_yi
                    bg_bid = world.get_bg_block(bx, by)
                    if bg_bid != AIR:
                        bg_surf = self._bg_block_surfs.get(bg_bid)
                        if bg_surf:
                            self.screen.blit(bg_surf, (sx, sy))
                    elif by > surface_ys.get(bx, 100):
                        self.screen.blit(self._cave_wall_surf, (sx, sy))
                    continue
                if bid == WATER:
                    level = world._water_level.get((bx, by), 8)
                    wsurf = self._water_surfs[level - 1]
                    wh = wsurf.get_height()
                    self.screen.blit(wsurf, (bx * BLOCK_SIZE - cam_xi,
                                             by * BLOCK_SIZE - cam_yi + BLOCK_SIZE - wh))
                    continue
                if bid == TILLED_SOIL:
                    moisture = world._soil_moisture.get((bx, by), 0)
                    tsurf = self._tilled_soil_surfs[1 if moisture >= 4 else 0]
                    self.screen.blit(tsurf, (bx * BLOCK_SIZE - cam_xi, by * BLOCK_SIZE - cam_yi))
                    continue
                if bid == ELEVATOR_CABLE_BLOCK:
                    sx = bx * BLOCK_SIZE - cam_xi
                    sy = by * BLOCK_SIZE - cam_yi
                    bg_bid = world.get_bg_block(bx, by)
                    if bg_bid != AIR:
                        bg_surf = self._bg_block_surfs.get(bg_bid)
                        if bg_surf:
                            self.screen.blit(bg_surf, (sx, sy))
                    elif by > surface_ys.get(bx, 100):
                        self.screen.blit(self._cave_wall_surf, (sx, sy))
                    pygame.draw.rect(self.screen, (55, 55, 65), (sx + 14, sy, 4, BLOCK_SIZE))
                    continue
                if bid == LADDER:
                    sx = bx * BLOCK_SIZE - cam_xi
                    sy = by * BLOCK_SIZE - cam_yi
                    bg_bid = world.get_bg_block(bx, by)
                    if bg_bid != AIR:
                        bg_surf = self._bg_block_surfs.get(bg_bid)
                        if bg_surf:
                            self.screen.blit(bg_surf, (sx, sy))
                    elif by > surface_ys.get(bx, 100):
                        self.screen.blit(self._cave_wall_surf, (sx, sy))
                    lsurf = self._block_surfs.get(LADDER)
                    if lsurf:
                        self.screen.blit(lsurf, (sx, sy))
                    continue
                if bid == ELEVATOR_STOP_BLOCK:
                    sx = bx * BLOCK_SIZE - cam_xi
                    sy = by * BLOCK_SIZE - cam_yi
                    BS = BLOCK_SIZE
                    bg_bid = world.get_bg_block(bx, by)
                    if bg_bid != AIR:
                        bg_surf = self._bg_block_surfs.get(bg_bid)
                        if bg_surf:
                            self.screen.blit(bg_surf, (sx, sy))
                    elif by > surface_ys.get(bx, 100):
                        self.screen.blit(self._cave_wall_surf, (sx, sy))
                    # Cable stub through center
                    pygame.draw.rect(self.screen, (55, 55, 65), (sx + 14, sy, 4, BS))
                    # Panel backplate
                    pygame.draw.rect(self.screen, (68, 72, 92), (sx + 3, sy + 6, BS - 6, BS - 12))
                    pygame.draw.rect(self.screen, (110, 116, 145), (sx + 3, sy + 6, BS - 6, BS - 12), 1)
                    # Call button
                    btn_cx = sx + BS // 2
                    btn_cy = sy + BS // 2 + 2
                    pygame.draw.circle(self.screen, (160, 165, 200), (btn_cx, btn_cy), 5)
                    pygame.draw.circle(self.screen, (200, 205, 240), (btn_cx, btn_cy), 5, 1)
                    # Floor indicator nub at top of panel
                    pygame.draw.rect(self.screen, (90, 95, 120), (sx + 10, sy + 8, BS - 20, 4))
                    continue
                if bid == MINE_TRACK_BLOCK:
                    sx = bx * BLOCK_SIZE - cam_xi
                    sy = by * BLOCK_SIZE - cam_yi
                    BS = BLOCK_SIZE
                    bg_bid = world.get_bg_block(bx, by)
                    if bg_bid != AIR:
                        bg_surf = self._bg_block_surfs.get(bg_bid)
                        if bg_surf:
                            self.screen.blit(bg_surf, (sx, sy))
                    elif by > surface_ys.get(bx, 100):
                        self.screen.blit(self._cave_wall_surf, (sx, sy))
                    # Two horizontal rails
                    pygame.draw.rect(self.screen, (140, 130, 115), (sx, sy + 10, BS, 3))
                    pygame.draw.rect(self.screen, (140, 130, 115), (sx, sy + BS - 13, BS, 3))
                    # Cross ties
                    for tx in range(sx + 2, sx + BS, 7):
                        pygame.draw.rect(self.screen, (100, 75, 50), (tx, sy + 8, 3, BS - 16))
                    continue
                if bid == MINE_TRACK_STOP_BLOCK:
                    sx = bx * BLOCK_SIZE - cam_xi
                    sy = by * BLOCK_SIZE - cam_yi
                    BS = BLOCK_SIZE
                    bg_bid = world.get_bg_block(bx, by)
                    if bg_bid != AIR:
                        bg_surf = self._bg_block_surfs.get(bg_bid)
                        if bg_surf:
                            self.screen.blit(bg_surf, (sx, sy))
                    elif by > surface_ys.get(bx, 100):
                        self.screen.blit(self._cave_wall_surf, (sx, sy))
                    # Rails and ties like normal track
                    pygame.draw.rect(self.screen, (140, 130, 115), (sx, sy + 10, BS, 3))
                    pygame.draw.rect(self.screen, (140, 130, 115), (sx, sy + BS - 13, BS, 3))
                    for tx in range(sx + 2, sx + BS, 7):
                        pygame.draw.rect(self.screen, (100, 75, 50), (tx, sy + 8, 3, BS - 16))
                    # Yellow-black stop post on the right edge
                    for i in range(4):
                        col = (210, 175, 25) if i % 2 == 0 else (35, 35, 35)
                        pygame.draw.rect(self.screen, col, (sx + BS - 6, sy + i * (BS // 4), 4, BS // 4))
                    continue
                if bid in (WOOD_DOOR_OPEN, IRON_DOOR_OPEN,
                           COBALT_DOOR_OPEN, CRIMSON_CEDAR_DOOR_OPEN,
                           TEAL_DOOR_OPEN, SAFFRON_DOOR_OPEN):
                    sx = bx * BLOCK_SIZE - cam_xi
                    sy = by * BLOCK_SIZE - cam_yi
                    bg_bid = world.get_bg_block(bx, by)
                    if bg_bid != AIR:
                        bg_surf = self._bg_block_surfs.get(bg_bid)
                        if bg_surf:
                            self.screen.blit(bg_surf, (sx, sy))
                    elif by > surface_ys.get(bx, 100):
                        self.screen.blit(self._cave_wall_surf, (sx, sy))
                    dsurf = self._block_surfs.get(bid)
                    if dsurf:
                        self.screen.blit(dsurf, (sx, sy))
                    continue
                surf = self._block_surfs.get(bid)
                # Block variants seeded by position for visual variety
                if bid in ALL_LOGS:
                    var = self._log_variants.get(bid)
                    if var:
                        surf = var[(bx * 97 + world.seed) % len(var)]
                elif bid in ALL_LEAVES:
                    var = self._leaf_variants.get(bid)
                    if var:
                        surf = var[(bx * 97 + by * 31 + world.seed) % len(var)]
                elif bid == GRASS:
                    surf = self._grass_variants[(bx * 73 + by * 41 + world.seed) % len(self._grass_variants)]
                elif bid == DIRT:
                    surf = self._dirt_variants[(bx * 59 + by * 83 + world.seed) % len(self._dirt_variants)]
                elif bid == SAND:
                    surf = self._sand_variants[(bx * 67 + by * 53 + world.seed) % len(self._sand_variants)]
                elif bid == SNOW:
                    surf = self._snow_variants[(bx * 43 + by * 79 + world.seed) % len(self._snow_variants)]
                biome = biomes[bx]
                biome_stone = self._biome_stone_surfs.get(biome)
                if bid == STONE and biome_stone:
                    surf = biome_stone
                dist = 0.0
                ore_visible = True
                if bid in RESOURCE_BLOCKS and px_blk is not None and not self.show_all_resources:
                    dist = ((bx - px_blk) ** 2 + (by - py_blk) ** 2) ** 0.5
                    underground = by > surface_ys.get(bx, 100)
                    ore_visible = (not underground) or (
                        dist <= warm and _los_clear(world, int(px_blk), int(py_blk), bx, by)
                    )
                    if not ore_visible or dist > warm:
                        depth = by - surface_ys.get(bx, 0)
                        strata_id = (LIMESTONE_STONE if depth < 60 else
                                     GRANITE_STONE   if depth < 120 else
                                     BASALT_STONE    if depth < 180 else
                                     MAGMATIC_STONE) if depth >= 15 else STONE
                        surf = biome_stone or self._block_surfs.get(strata_id, self._block_surfs.get(STONE))
                    elif dist > detect:
                        biome_hints = self._biome_resource_hint_surfs.get(biome, self._resource_hint_surfs)
                        surf = biome_hints.get(bid, self._resource_hint_surfs[bid])
                if bid == TOWN_FLAG_BLOCK:
                    try:
                        from towns import REGIONS, get_town_for_block
                        town = get_town_for_block(world, bx, by)
                        if town:
                            region = REGIONS.get(town.region_id)
                            if region:
                                surf = self._get_town_flag_surf(
                                    region.region_id, region.leader_color)
                    except Exception:
                        pass  # fall through to default surf
                if bid == OUTPOST_FLAG_BLOCK:
                    try:
                        from outposts import OUTPOSTS, OUTPOST_FLAG_COLORS
                        best = min(OUTPOSTS.values(),
                                   key=lambda op: abs(op.center_bx - bx),
                                   default=None)
                        if best is not None:
                            col = OUTPOST_FLAG_COLORS.get(best.outpost_type)
                            if col:
                                surf = self._get_outpost_flag_surf(best.outpost_type, col)
                    except Exception:
                        pass  # fall through to default surf
                if surf:
                    sx = bx * BLOCK_SIZE - cam_xi
                    sy = by * BLOCK_SIZE - cam_yi
                    self.screen.blit(surf, (sx, sy))
                    if bid in _SHIMMER_BLOCKS and ore_visible and (px_blk is None or dist <= detect):
                        now = pygame.time.get_ticks()
                        sc = _SHIMMER_BLOCKS[bid]
                        h = bx * 1283 + by * 7919
                        for i in range(4):
                            phase = (h + i * 4999) % 65536
                            if ((now + phase) // 350) % 5 == 0:
                                spx = 1 + (h * (i + 3) * 43) % 28
                                spy = 1 + (h * (i + 3) * 97) % 28
                                pygame.draw.rect(self.screen, sc, (sx + spx, sy + spy, 2, 2))

        self._draw_all_sculptures(world)
        self._draw_all_tapestries(world)
        self._draw_pottery_displays(world, cam_xi, cam_yi)
        self._draw_wildflower_displays(world, cam_xi, cam_yi)
        self._draw_garden_blocks(world, cam_xi, cam_yi)

    def _draw_pottery_displays(self, world, cam_xi, cam_yi):
        """Overlay a vase silhouette on every occupied pottery display pedestal."""
        if not world.pottery_display_data:
            return
        clay_color  = (185, 120, 80)
        dark_clay   = _darken(clay_color, 35)
        for (bx, by), piece in world.pottery_display_data.items():
            sx = bx * BLOCK_SIZE - cam_xi
            sy = by * BLOCK_SIZE - cam_yi
            if sx < -BLOCK_SIZE or sx > self.screen.get_width() or sy < -BLOCK_SIZE or sy > self.screen.get_height():
                continue
            profile = piece.profile
            n = len(profile)
            if n == 0:
                continue
            # Draw the vase silhouette scaled to fit within the arch opening (12w × 18h px, centred)
            row_h = max(1, 18 // n)
            top_y = sy + 7 - row_h * n // 2 + 1
            cx = sx + BLOCK_SIZE // 2
            scale = 12.0 / max(profile) if max(profile) > 0 else 1.0
            for row, rad in enumerate(profile):
                ry = top_y + row * row_h
                w = max(1, int(rad * scale))
                pygame.draw.rect(self.screen, clay_color, (cx - w, ry, w * 2, row_h))
                pygame.draw.rect(self.screen, dark_clay,  (cx - w, ry, w * 2, 1))

    # ------------------------------------------------------------------
    # Draw sculptures (per-instance background art)
    # ------------------------------------------------------------------

    def _draw_sculpture_at(self, sc, root_bx, root_by):
        actual_cols    = len(sc.grid[0]) if sc.grid and sc.grid[0] else 8
        rows_per_block = len(sc.grid) // max(1, sc.height)
        CELL_W = BLOCK_SIZE // actual_cols
        CELL_H = BLOCK_SIZE // rows_per_block
        cam_xi = int(self.cam_x)
        cam_yi = int(self.cam_y)
        base_color = sc.color
        hi_color   = tuple(min(255, c + 25) for c in base_color)
        lo_color   = tuple(max(0,   c - 35) for c in base_color)
        rows_total = len(sc.grid)
        for row_idx in range(rows_total - 1, -1, -1):
            row = sc.grid[row_idx]
            rows_from_bottom = rows_total - 1 - row_idx
            block_offset     = rows_from_bottom // rows_per_block
            local_row        = rows_from_bottom % rows_per_block
            world_y = root_by - block_offset
            screen_x = root_bx * BLOCK_SIZE - cam_xi
            screen_y = world_y  * BLOCK_SIZE - cam_yi + local_row * CELL_H
            for col_idx, filled in enumerate(row):
                if not filled:
                    continue
                color = hi_color if col_idx % 2 == 0 else lo_color
                pygame.draw.rect(self.screen, color,
                                 (screen_x + col_idx * CELL_W, screen_y, CELL_W, CELL_H))

    def _draw_all_sculptures(self, world):
        for pos, data in world.sculpture_data.items():
            if isinstance(data, dict) and "root" in data:
                continue   # body pointer — skip; root draws the whole sculpture
            bx, by = pos
            self._draw_sculpture_at(data, bx, by)

    # ------------------------------------------------------------------
    # Draw custom tapestries (per-instance background fabric art)
    # ------------------------------------------------------------------

    def _draw_tapestry_at(self, tp, root_bx, root_by):
        actual_cols    = len(tp.grid[0]) if tp.grid and tp.grid[0] else 16
        rows_per_block = len(tp.grid) // max(1, tp.height)
        tp_width       = getattr(tp, "width", 1)
        CELL_W = (BLOCK_SIZE * tp_width) // actual_cols
        CELL_H = BLOCK_SIZE // rows_per_block
        cam_xi = int(self.cam_x)
        cam_yi = int(self.cam_y)
        base_color = tp.color
        hi_color   = tuple(min(255, c + 30) for c in base_color)
        lo_color   = tuple(max(0,   c - 38) for c in base_color)
        rows_total = len(tp.grid)
        for row_idx in range(rows_total - 1, -1, -1):
            row = tp.grid[row_idx]
            rows_from_bottom = rows_total - 1 - row_idx
            block_offset     = rows_from_bottom // rows_per_block
            local_row        = rows_from_bottom % rows_per_block
            world_y  = root_by - block_offset
            screen_x = root_bx * BLOCK_SIZE - cam_xi
            screen_y = world_y  * BLOCK_SIZE - cam_yi + local_row * CELL_H
            for col_idx, filled in enumerate(row):
                if not filled:
                    continue
                # Alternating warp/weft color for woven texture
                color = hi_color if row_idx % 2 == 0 else lo_color
                pygame.draw.rect(self.screen, color,
                                 (screen_x + col_idx * CELL_W, screen_y, CELL_W, CELL_H))
                # Warp line down the center of each cell (only when cell is tall enough)
                if CELL_H >= 3 and CELL_W >= 2:
                    mid_x = screen_x + col_idx * CELL_W + CELL_W // 2
                    shade = tuple(max(0, c - 25) for c in color)
                    pygame.draw.line(self.screen, shade,
                                     (mid_x, screen_y), (mid_x, screen_y + CELL_H - 1))

    def _draw_all_tapestries(self, world):
        for pos, data in world.tapestry_data.items():
            if isinstance(data, dict) and "root" in data:
                continue   # body pointer — skip; root draws the whole tapestry
            bx, by = pos
            self._draw_tapestry_at(data, bx, by)

    def _draw_garden_blocks(self, world, cam_xi, cam_yi):
        import math as _math
        if not world.garden_data:
            return
        petal_colors = [(255, 220, 30), (255, 100, 160), (255, 255, 255),
                        (180, 120, 255), (255, 160, 40)]
        for (bx, by), flowers in world.garden_data.items():
            if not flowers:
                continue
            sx = bx * BLOCK_SIZE - cam_xi
            sy = by * BLOCK_SIZE - cam_yi
            if sx < -BLOCK_SIZE or sx > self.screen.get_width() or sy < -BLOCK_SIZE or sy > self.screen.get_height():
                continue
            count = min(len(flowers), 5)
            # Spread flowers evenly across the soil area (x: 5..27, y: 11..25)
            for i, wf in enumerate(flowers[:count]):
                fx = 5 + int(i * 22 / max(count - 1, 1)) if count > 1 else 16
                fy = 13 + (i % 2) * 5
                stem_top = fy - 6
                pygame.draw.line(self.screen, (50, 130, 40), (sx + fx, sy + fy), (sx + fx, sy + stem_top), 1)
                pc = wf.primary_color
                sc = wf.secondary_color
                for j in range(5):
                    ang = j * 2 * _math.pi / 5 - _math.pi / 2
                    px2 = int(sx + fx + 3 * _math.cos(ang))
                    py2 = int(sy + stem_top + 3 * _math.sin(ang))
                    pygame.draw.circle(self.screen, pc if j % 2 == 0 else sc, (px2, py2), 2)
                pygame.draw.circle(self.screen, wf.center_color, (sx + fx, sy + stem_top), 1)

    def _draw_wildflower_displays(self, world, cam_xi, cam_yi):
        import math as _math
        if not world.wildflower_display_data:
            return
        for (bx, by), wf in world.wildflower_display_data.items():
            if wf is None:
                continue
            sx = bx * BLOCK_SIZE - cam_xi
            sy = by * BLOCK_SIZE - cam_yi
            if sx < -BLOCK_SIZE or sx > self.screen.get_width() or sy < -BLOCK_SIZE or sy > self.screen.get_height():
                continue
            # Stem inside the vase
            pygame.draw.line(self.screen, (50, 140, 40), (sx + 16, sy + 14), (sx + 16, sy + 25), 1)
            # 5 petals using the flower's colors
            petal_c = wf.primary_color + (220,)
            sec_c   = wf.secondary_color + (180,)
            for i in range(5):
                ang = i * 2 * _math.pi / 5 - _math.pi / 2
                px = int(sx + 16 + 5 * _math.cos(ang))
                py = int(sy + 11 + 5 * _math.sin(ang))
                pygame.draw.circle(self.screen, petal_c if i % 2 == 0 else sec_c, (px, py), 3)
            pygame.draw.circle(self.screen, wf.center_color, (sx + 16, sy + 11), 2)

    # ------------------------------------------------------------------
    # Draw player
    # ------------------------------------------------------------------

    def draw_player(self, player):
        px = int(player.x - self.cam_x)
        py = int(player.y - self.cam_y)
        head_h = 10
        body_h = PLAYER_H - head_h
        # Head
        pygame.draw.rect(self.screen, (255, 210, 160), (px + 2, py, PLAYER_W - 4, head_h))
        # Eye on facing side
        eye_x = (px + PLAYER_W - 6) if player.facing == 1 else (px + 2)
        pygame.draw.rect(self.screen, (30, 30, 30), (eye_x, py + 3, 3, 3))
        # Body
        pygame.draw.rect(self.screen, (70, 120, 190), (px, py + head_h, PLAYER_W, body_h))
        # Arm on facing side (pickaxe hand)
        arm_x = (px + PLAYER_W) if player.facing == 1 else (px - 3)
        pygame.draw.rect(self.screen, (255, 210, 160), (arm_x, py + head_h + 2, 3, 8))
        # Legs
        pygame.draw.rect(self.screen, (50, 80, 140), (px, py + head_h + body_h - 6, 8, 6))
        pygame.draw.rect(self.screen, (50, 80, 140), (px + PLAYER_W - 8, py + head_h + body_h - 6, 8, 6))

